/**
 * tier8：impl 头审计 — impl [for Type] { 基本形态。
 */
int32_t parser_asm_stretch_impl_header_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer lex_cur;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_IMPL)
    return 0;
  parser_asm_lex_from_result_val_into(&lex_cur, r);
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind != (int32_t)TOKEN_IDENT || r.tok.ident_len <= 0)
    return 0;
  parser_asm_lex_from_result_val_into(&lex_cur, r);
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind == (int32_t)TOKEN_FOR) {
    parser_asm_lex_from_result_val_into(&lex_cur, r);
    lexer_next_into(&r, lex_cur, source);
    if (r.tok.kind != (int32_t)TOKEN_IDENT || r.tok.ident_len <= 0)
      return 0;
    parser_asm_lex_from_result_val_into(&lex_cur, r);
    lexer_next_into(&r, lex_cur, source);
  }
  return r.tok.kind == (int32_t)TOKEN_LBRACE ? 1 : 0;
}

/**
 * tier8：function 头审计 — [async] function name ( 基本形态。
 */
int32_t parser_asm_stretch_function_header_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer lex_cur;
  if (!source)
    return 0;
  lex_cur = lex;
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind == (int32_t)TOKEN_ASYNC) {
    parser_asm_lex_from_result_val_into(&lex_cur, r);
    lexer_next_into(&r, lex_cur, source);
  }
  if (r.tok.kind != (int32_t)TOKEN_FUNCTION)
    return 0;
  parser_asm_lex_from_result_val_into(&lex_cur, r);
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind != (int32_t)TOKEN_IDENT || r.tok.ident_len <= 0)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  return r.tok.kind == (int32_t)TOKEN_LPAREN ? 1 : 0;
}

/**
 * tier9：match 关键字审计 — match 后须能到达 '{'（粗探，不写 arena）。
 */
int32_t parser_asm_stretch_match_kw_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer lex_cur;
  int32_t guard;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_MATCH)
    return 0;
  lex_cur = r.next_lex;
  guard = 0;
  for (;;) {
    if (guard++ > 512)
      return 0;
    lexer_next_into(&r, lex_cur, source);
    if (r.tok.kind == (int32_t)TOKEN_LBRACE)
      return 1;
    if (r.tok.kind == (int32_t)TOKEN_EOF || r.tok.kind == (int32_t)TOKEN_SEMICOLON)
      return 0;
    lex_cur = r.next_lex;
  }
}

/**
 * tier9：else if 链审计 — else if ( 基本形态。
 */
int32_t parser_asm_stretch_else_if_chain_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_ELSE)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  if (r.tok.kind != (int32_t)TOKEN_IF)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  return r.tok.kind == (int32_t)TOKEN_LPAREN ? 1 : 0;
}

/**
 * tier9：类型引用粗审计 — * / 标量 / ident 类型后缀可跳过。
 */
int32_t parser_asm_stretch_type_ref_peek_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer after;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind == (int32_t)TOKEN_STAR)
    return 1;
  if (!parser_asm_stretch_is_type_start_kind_c(r.tok.kind))
    return 0;
  after = parser_asm_stretch_skip_type_suffix_c(r.next_lex, source);
  return after.pos != lex.pos ? 1 : 0;
}

/**
 * tier9：顶层 token 链审计 — peek 至多 4 个 kind 并粗分类打分。
 */
int32_t parser_asm_stretch_toplevel_kind_peek_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  int32_t kinds[4];
  int32_t n;
  int32_t score;
  if (!source)
    return 0;
  n = parser_asm_stretch_peek_kind_chain_c(lex, source, kinds, 4);
  if (n <= 0)
    return 0;
  score = kinds[0];
  if (n >= 2)
    score += parser_asm_stretch_classify_toplevel_c(kinds[0], kinds[1], n >= 3 ? kinds[2] : (int32_t)TOKEN_EOF);
  return score > 0 ? 1 : 0;
}

/**
 * tier9：return 语句审计 — return [expr] ; 粗形态。
 */
int32_t parser_asm_stretch_return_stmt_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer lex_cur;
  int32_t guard;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_RETURN)
    return 0;
  lex_cur = r.next_lex;
  guard = 0;
  for (;;) {
    if (guard++ > 256)
      return 0;
    lexer_next_into(&r, lex_cur, source);
    if (r.tok.kind == (int32_t)TOKEN_SEMICOLON)
      return 1;
    if (r.tok.kind == (int32_t)TOKEN_EOF)
      return 0;
    lex_cur = r.next_lex;
  }
}

/**
 * tier10：break/continue 语句审计 — break/continue ;
 */
int32_t parser_asm_stretch_break_continue_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source,
                                                  int32_t want_break) {
  struct parser_asm_lexer_result r;
  int32_t want;
  if (!source)
    return 0;
  want = want_break != 0 ? (int32_t)TOKEN_BREAK : (int32_t)TOKEN_CONTINUE;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != want)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  return r.tok.kind == (int32_t)TOKEN_SEMICOLON ? 1 : 0;
}

/**
 * tier10：else 分支审计 — else { / else if ( 基本形态。
 */
int32_t parser_asm_stretch_else_stmt_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_ELSE)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  if (r.tok.kind == (int32_t)TOKEN_IF || r.tok.kind == (int32_t)TOKEN_LBRACE)
    return 1;
  return 0;
}

/**
 * tier10：import 路径点分 segment 名审计（IDENT 段须合法 ident）。
 */
int32_t parser_asm_stretch_import_dot_segment_audit_c(struct parser_asm_lexer_result r,
                                                      struct parser_asm_slice_u8 *source) {
  uint8_t seg_buf[64];
  int32_t seg_len;
  int32_t bi;
  if (!source || !source->data)
    return 0;
  if (r.tok.kind == (int32_t)TOKEN_I32)
    return 1;
  if (r.tok.kind == (int32_t)TOKEN_ASYNC)
    return 1;
  if (r.tok.kind != (int32_t)TOKEN_IDENT || r.tok.ident_len <= 0 || r.tok.ident_len > 63)
    return 0;
  seg_len = r.tok.ident_len;
  for (bi = 0; bi < seg_len && bi < 63; bi++) {
    if (r.token_start + (size_t)bi < source->length)
      seg_buf[bi] = source->data[r.token_start + (size_t)bi];
  }
  seg_buf[bi < 63 ? bi : 63] = 0;
  return parser_asm_stretch_bind_name_validate_c(seg_buf, seg_len);
}

/**
 * tier10：if/while 条件 int as T 粗审计。
 */
int32_t parser_asm_stretch_cond_int_as_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer_result r2;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_INT && r.tok.kind != (int32_t)TOKEN_I32)
    return 0;
  lexer_next_into(&r2, r.next_lex, source);
  return r2.tok.kind == (int32_t)TOKEN_AS ? 1 : 0;
}

