/**
 * tier11：library 单参 bool 返回形态审计 — function name ( params ) 粗校验。
 */
int32_t parser_asm_stretch_library_fn_shape_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer lex_cur;
  if (!source)
    return 0;
  if (parser_asm_stretch_function_header_audit_c(lex, source) == 0)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_FUNCTION)
    return 0;
  parser_asm_lex_from_result_val_into(&lex_cur, r);
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind == (int32_t)TOKEN_SPAWN) {
    parser_asm_lex_from_result_val_into(&lex_cur, r);
    lexer_next_into(&r, lex_cur, source);
  }
  if (r.tok.kind != (int32_t)TOKEN_IDENT)
    return 0;
  parser_asm_lex_from_result_val_into(&lex_cur, r);
  lexer_next_into(&r, lex_cur, source);
  if (r.tok.kind != (int32_t)TOKEN_LPAREN)
    return 0;
  lex_cur = r.next_lex;
  return parser_asm_stretch_fn_param_list_audit_c(&lex_cur, source);
}

/**
 * tier12：primary 首 token 形态审计（INT/IDENT/if/match/panic/@ 等扩面）。
 */
int32_t parser_asm_stretch_primary_head_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  int32_t score;
  if (!source)
    return 0;
  score = 0;
  lexer_next_into(&r, lex, source);
  switch (r.tok.kind) {
  case (int32_t)TOKEN_INT:
  case (int32_t)TOKEN_FLOAT:
    score += 1;
    break;
  case (int32_t)TOKEN_TRUE:
  case (int32_t)TOKEN_FALSE:
    score += 1;
    break;
  case (int32_t)TOKEN_IDENT:
    (void)parser_asm_stretch_bind_name_validate_c(source->data + r.token_start, r.tok.ident_len);
    score += 2;
    break;
  case (int32_t)TOKEN_LPAREN:
  case (int32_t)TOKEN_LBRACKET:
    score += 1;
    break;
  case (int32_t)TOKEN_IF:
    (void)parser_asm_stretch_if_header_audit_c(lex, source);
    score += 3;
    break;
  case (int32_t)TOKEN_MATCH:
    (void)parser_asm_stretch_match_kw_audit_c(lex, source);
    score += 3;
    break;
  case (int32_t)TOKEN_PANIC:
    score += 2;
    break;
  case (int32_t)TOKEN_AT:
    score += 2;
    break;
  case (int32_t)TOKEN_BREAK:
    (void)parser_asm_stretch_break_continue_audit_c(lex, source, 1);
    score += 1;
    break;
  case (int32_t)TOKEN_CONTINUE:
    (void)parser_asm_stretch_break_continue_audit_c(lex, source, 0);
    score += 1;
    break;
  default:
    break;
  }
  return score;
}

