/**
 * tier13：`as type` 后缀链粗探（不修改 out）。
 */
int32_t parser_asm_stretch_as_suffix_chain_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  int32_t n;
  int32_t guard;
  if (!source)
    return 0;
  n = 0;
  guard = 0;
  lexer_next_into(&r, lex, source);
  while (r.tok.kind == (int32_t)TOKEN_AS) {
    n++;
    if (n > 16 || guard++ > 32)
      return n;
    parser_asm_lex_from_result_val_into(&lex, r);
    lexer_next_into(&r, lex, source);
    if (r.tok.kind == (int32_t)TOKEN_STAR) {
      parser_asm_lex_from_result_val_into(&lex, r);
      lexer_next_into(&r, lex, source);
    }
    if (!parser_asm_stretch_is_type_start_kind_c(r.tok.kind))
      return n;
    lex = parser_asm_stretch_skip_type_suffix_c(r.next_lex, source);
    lexer_next_into(&r, lex, source);
  }
  return n;
}

/**
 * tier13：一元前缀 await/run/spawn/-,!,& 粗探。
 */
int32_t parser_asm_stretch_unary_prefix_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  struct parser_asm_lexer_result r2;
  int32_t depth;
  if (!source)
    return 0;
  depth = 0;
  lexer_next_into(&r, lex, source);
  while (r.tok.kind == (int32_t)TOKEN_AWAIT || r.tok.kind == (int32_t)TOKEN_RUN || r.tok.kind == (int32_t)TOKEN_SPAWN
         || r.tok.kind == (int32_t)TOKEN_MINUS || r.tok.kind == (int32_t)TOKEN_BANG) {
    depth++;
    if (depth > 16)
      return depth;
    parser_asm_lex_from_result_val_into(&lex, r);
    lexer_next_into(&r, lex, source);
  }
  if (r.tok.kind == (int32_t)TOKEN_AMP) {
    lexer_next_into(&r2, r.next_lex, source);
    if (r2.tok.kind != (int32_t)TOKEN_AMP)
      depth++;
  }
  return depth;
}

