/**
 * tier13：@shuffle/@select SIMD 内建名审计。
 */
int32_t parser_asm_stretch_simd_builtin_audit_c(struct parser_asm_lexer_result r_at,
                                                struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  int32_t nlen;
  size_t start;
  if (!source)
    return 0;
  if (r_at.tok.kind != (int32_t)TOKEN_AT)
    return 0;
  lexer_next_into(&r, r_at.next_lex, source);
  if (r.tok.kind != (int32_t)TOKEN_IDENT)
    return 0;
  nlen = r.tok.ident_len;
  start = r.token_start;
  if (nlen == 7 && start + 6 < source->length && source->data[start] == 115 && source->data[start + 1] == 104
      && source->data[start + 2] == 117 && source->data[start + 3] == 102 && source->data[start + 4] == 102
      && source->data[start + 5] == 108 && source->data[start + 6] == 101)
    return 1;
  if (nlen == 6 && start + 5 < source->length && source->data[start] == 115 && source->data[start + 1] == 101
      && source->data[start + 2] == 108 && source->data[start + 3] == 101 && source->data[start + 4] == 99
      && source->data[start + 5] == 116)
    return 1;
  return 0;
}

/**
 * tier13：struct literal 字段 ident : 形态粗探。
 */
int32_t parser_asm_stretch_struct_lit_fields_probe_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source,
                                                     int32_t *out_field_count) {
  struct parser_asm_lexer_result r;
  int32_t nf;
  int32_t guard;
  int32_t depth;
  if (!source)
    return 0;
  nf = 0;
  guard = 0;
  lexer_next_into(&r, lex, source);
  while (r.tok.kind != (int32_t)TOKEN_RBRACE && r.tok.kind != (int32_t)TOKEN_EOF) {
    if (guard++ > 64)
      return 0;
    if (r.tok.kind != (int32_t)TOKEN_IDENT)
      return 0;
    (void)parser_asm_stretch_bind_name_validate_c(source->data + r.token_start, r.tok.ident_len);
    lexer_next_into(&r, r.next_lex, source);
    if (r.tok.kind != (int32_t)TOKEN_COLON)
      return 0;
    nf++;
    lex = r.next_lex;
    depth = 0;
    lexer_next_into(&r, lex, source);
    while (r.tok.kind != (int32_t)TOKEN_EOF) {
      if (guard++ > 512)
        return 0;
      if (depth == 0 && (r.tok.kind == (int32_t)TOKEN_COMMA || r.tok.kind == (int32_t)TOKEN_RBRACE))
        break;
      if (r.tok.kind == (int32_t)TOKEN_LPAREN || r.tok.kind == (int32_t)TOKEN_LBRACE)
        depth++;
      else if (r.tok.kind == (int32_t)TOKEN_RPAREN || r.tok.kind == (int32_t)TOKEN_RBRACE)
        depth--;
      parser_asm_lex_from_result_val_into(&lex, r);
      lexer_next_into(&r, lex, source);
    }
    if (r.tok.kind == (int32_t)TOKEN_COMMA) {
      lex = r.next_lex;
      lexer_next_into(&r, lex, source);
      continue;
    }
    break;
  }
  if (out_field_count)
    *out_field_count = nf;
  return r.tok.kind == (int32_t)TOKEN_RBRACE ? 1 : 0;
}

/**
 * tier13：数组字面量 [ 首 token 粗探。
 */
int32_t parser_asm_stretch_array_lit_head_audit_c(struct parser_asm_lexer lex, struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  if (!source)
    return 0;
  lexer_next_into(&r, lex, source);
  if (r.tok.kind != (int32_t)TOKEN_LBRACKET)
    return 0;
  lexer_next_into(&r, r.next_lex, source);
  return r.tok.kind == (int32_t)TOKEN_RBRACKET || r.tok.kind == (int32_t)TOKEN_INT
         || r.tok.kind == (int32_t)TOKEN_IDENT || r.tok.kind == (int32_t)TOKEN_TRUE
         || r.tok.kind == (int32_t)TOKEN_FALSE ? 1 : 0;
}

/**
 * tier14：IDENT 后缀链粗探 — `.field` / `[idx]` / `(args)` 计数。
 */
int32_t parser_asm_stretch_primary_suffix_chain_probe_c(struct parser_asm_lexer lex,
                                                        struct parser_asm_slice_u8 *source) {
  struct parser_asm_lexer_result r;
  int32_t score;
  int32_t guard;
  if (!source)
    return 0;
  score = 0;
  guard = 0;
  lexer_next_into(&r, lex, source);
  while (guard++ < 64) {
    if (r.tok.kind == (int32_t)TOKEN_DOT) {
      score += 2;
      lexer_next_into(&r, r.next_lex, source);
      if (r.tok.kind != (int32_t)TOKEN_IDENT)
        break;
      (void)parser_asm_stretch_bind_name_validate_c(source->data + r.token_start, r.tok.ident_len);
      parser_asm_lex_from_result_val_into(&lex, r);
      lexer_next_into(&r, lex, source);
    } else if (r.tok.kind == (int32_t)TOKEN_LBRACKET) {
      score += 2;
      parser_asm_stretch_skip_balanced_brackets_into_c(&lex, r.next_lex, source);
      lexer_next_into(&r, lex, source);
    } else if (r.tok.kind == (int32_t)TOKEN_LPAREN) {
      score += 3;
      parser_asm_skip_balanced_parens_into_slice_c(&lex, r.next_lex, source);
      lexer_next_into(&r, lex, source);
    } else {
      break;
    }
  }
  return score;
}

